def encrypt_aes(plaintext: str, key: bytes) -> str:
    if not plaintext or str(plaintext).strip() in ['', 'None', 'nan', 'SIN CLAVE']: 
        return "SIN_DATO"
    if len(str(plaintext)) > 500: return "DATO_INVALIDO"
    iv = os.urandom(16)
    cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
    encryptor = cipher.encryptor()
    plaintext_bytes = str(plaintext).encode('utf-8')
    pad_len = 16 - (len(plaintext_bytes) % 16)
    plaintext_bytes += bytes([pad_len] * pad_len)
    ciphertext = encryptor.update(plaintext_bytes) + encryptor.finalize()
    return f"{iv.hex()}:{ciphertext.hex()}"

def generate_hash(value: str) -> str:
    if not value or str(value).strip() == '': return "hash_vacio"
    return hashlib.sha256(str(value).encode('utf-8')).hexdigest()[:50] 

def clean_money(val):
    if not val: return 0.0
    val_str = str(val).upper().strip()
    if val_str in ['NO', 'NO FACTURAR', 'FREE', 'VACÍO', '0', 'SIN MOVIMIENTO', 'ESTÁ EN OTRA FACTURA', 'COBRAR MARZO', 'DE BAJA']: 
        return 0.0
    val_str = val_str.replace('$', '').replace('.', '').replace(',', '.').replace('?', '').replace('!', '').strip()
    try: 
        num = float(val_str)
        if num >= 1000000000000: return 0.0
        return num
    except: 
        return 0.0

def safe_str(val, max_len=50):
    if not val: return ''
    s = str(val).split('#')[0].strip() 
    return s[:max_len]

def map_estado_pago(val):
    v = str(val).upper().strip()
    if 'PAGADO' in v and 'NO PAGADO' not in v: return 'AL DIA'
    if 'FREE' in v: return 'AL DIA'
    if 'AL DIA' in v: return 'AL DIA'
    if 'NO PAGADO' in v: return 'NO PAGADO'
    return 'SERVICIO SUSPENDIDO'

def map_estado_f29(val):
    v = str(val).upper().strip()
    if 'PENDIENTE' in v: return 'PENDIENTE'
    if 'DECLARADO' in v: return 'DECLARADO'
    return 'NO DECLARAR'

