def ejecutar_carga_directa():
    conn = None
    try:
        conn = psycopg2.connect(user=DB_USER, password=DB_PASSWORD, host=DB_HOST, port=DB_PORT, database=DB_DATABASE)
        cur = conn.cursor()
        
        cur.execute("TRUNCATE TABLE empresa, empresa_credenciales CASCADE;")
        conn.commit()

        # -------------------------------------------------------------
        # NUEVO: RECREAR AUTOMÁTICAMENTE LOS PLANES QUE SE BORRARON
        # -------------------------------------------------------------
        cur.execute("SELECT UPPER(nombre) FROM plan;")
        planes_existentes = [row[0] for row in cur.fetchall()]
        
        planes_default = ["FREE", "GO", "EMPRENDEDOR", "EXECUTIVE", "FULL EMPRENDEDOR"]
        for p in planes_default:
            if p not in planes_existentes:
                cur.execute("INSERT INTO plan (nombre, precio_base) VALUES (%s, 0)", (p,))
        conn.commit()
        # -------------------------------------------------------------

        cur.execute("SELECT id, nombre FROM plan;")
        mapa_planes = {nombre.upper().strip(): id_plan for id_plan, nombre in cur.fetchall()}
        
        empresas_list = []
        credenciales_list = []
        ruts_empresas_procesados = set()
        ruts_rl_procesados = set()

        f = io.StringIO(DATOS_RAW.strip())
        reader = csv.reader(f, delimiter='\t')
        headers = next(reader) 

        for idx, row in enumerate(reader):
            if not row or len(row) < 12: continue
            
            razon_social = safe_str(row[0], 255)
            rut_sii = safe_str(row[11], 20).replace('.', '')
            if not rut_sii or rut_sii.upper() == 'SIN RUT': continue 
                
            rut_empresa_hash = generate_hash(rut_sii)
            if rut_empresa_hash in ruts_empresas_procesados: continue
            ruts_empresas_procesados.add(rut_empresa_hash)
            
            rut_rl = safe_str(row[14], 20).replace('.', '')
            if not rut_rl or rut_rl.upper() == 'SIN RUT':
                rut_rl_enc = None
                rut_rl_hash = None
            else:
                hash_rl = generate_hash(rut_rl)
                if hash_rl in ruts_rl_procesados:
                    rut_rl_enc = None
                    rut_rl_hash = None
                else:
                    rut_rl_enc = encrypt_aes(rut_rl, ENCRYPTION_KEY)
                    rut_rl_hash = hash_rl
                    ruts_rl_procesados.add(hash_rl)

            email = safe_str(row[13], 255)
            clave_web = safe_str(row[12], 255) 
            clave_sii = safe_str(row[22], 255) if len(row) > 22 else "SIN_DATO" 
            
            empresa_id = str(uuid.uuid4())
            rut_enc = encrypt_aes(rut_sii, ENCRYPTION_KEY)

            estado_f29_limpio = map_estado_f29(row[17] if len(row) > 17 else '')
            estado_pago_limpio = map_estado_pago(row[18] if len(row) > 18 else '')

            plan_texto_excel = safe_str(row[3], 50).upper()
            plan_id = None
            for nombre_bd, p_id in mapa_planes.items():
                if nombre_bd in plan_texto_excel or plan_texto_excel in nombre_bd:
                    plan_id = p_id
                    break

            neto_pagar = clean_money(row[6]) if len(row) > 6 else 0.0
            monto_bruto = clean_money(row[7]) if len(row) > 7 else 0.0
            renta_monto = clean_money(row[9]) if len(row) > 9 else 0.0
            impuesto_unico = clean_money(row[20]) if len(row) > 20 else 0.0
            compras = clean_money(row[24]) if len(row) > 24 else 0.0
            ventas = clean_money(row[25]) if len(row) > 25 else 0.0
            fact_total = clean_money(row[26]) if len(row) > 26 else 0.0
            renta_mzo_neto = clean_money(row[28]) if len(row) > 28 else 0.0
            renta_mzo_bruto = clean_money(row[29]) if len(row) > 29 else 0.0

            empresas_list.append((
                empresa_id, plan_id, razon_social, rut_enc, rut_empresa_hash,
                "Sin Giro Especifico", "Sin Regimen", safe_str(row[15], 50) if len(row) > 15 else '', 
                email, estado_pago_limpio, estado_f29_limpio, neto_pagar, 100, 
                safe_str(row[21], 255) if len(row) > 21 else '', rut_rl_enc, rut_rl_hash, 
                compras, ventas, fact_total, monto_bruto, safe_str(row[8], 50) if len(row) > 8 else '', 
                row[1].upper() == 'SI' if len(row) > 1 else False, safe_str(row[2], 100) if len(row) > 2 else '', 
                renta_monto, impuesto_unico, renta_mzo_neto, renta_mzo_bruto, None, '', ''
            ))

            credenciales_list.append((
                empresa_id, rut_enc, encrypt_aes(email, ENCRYPTION_KEY),
                encrypt_aes(clave_sii, ENCRYPTION_KEY), encrypt_aes(clave_web, ENCRYPTION_KEY)
            ))

        if empresas_list:
            execute_values(cur, """
                INSERT INTO empresa (
                    id, plan_id, razon_social, rut_encrypted, rut_hash, giro, regimen_tributario, 
                    telefono_corporativo, email_corporativo, estado_pago, estado_f29, impuesto_pagar, score,
                    nombre_rep, rut_rep_encrypted, rut_rep_hash, compras_mensuales, ventas_mensuales, 
                    facturacion_total, monto_bruto, nro_factura, contrato_renta, estado_formulario_renta, 
                    monto_renta, impuesto_unico, renta_marzo_neto, renta_marzo_bruto, fecha_pago, nota_urgente, whatsapp
                ) VALUES %s
            """, empresas_list)

            execute_values(cur, """
                INSERT INTO empresa_credenciales (
                    empresa_id, sii_rut_encrypted, sii_email_encrypted, sii_password_encrypted, web_password_encrypted
                ) VALUES %s
            """, credenciales_list)
            conn.commit()
            print("[EXITO TOTAL] ¡Planes y Contraseñas restaurados a la perfección!")
        
        cur.close(); conn.close()
    except Exception as e:
        if conn: conn.rollback(); conn.close()
        print(f"[ERROR] {e}")

if __name__ == "__main__":
    ejecutar_carga_directa()